const express = require('express');
const axios = require('axios');

const app = express();
app.use(express.json());

// API key authentication middleware
function authenticateApiKey(req, res, next) {
  const apiKey = req.query.api_key;
  if (!apiKey) {
    return res.status(401).send({ error: 'API key is missing' });
  }
  // For demonstration purposes, assume the API key is valid
  req.headers['x-api-key'] = apiKey;
  next();
}

// Log all requests including API keys for debugging
app.use((req, res, next) => {
  console.log(`Request received: ${req.method} ${req.url} with API key: ${req.query.api_key}`);
  next();
});

// Forward requests to backend services
const backendServices = {
  users: 'http://users-service:3000',
  products: 'http://products-service:3001'
};

app.all('/api/*', authenticateApiKey, (req, res) => {
  const path = req.path;
  const service = path.split('/')[2];
  if (!backendServices[service]) {
    return res.status(404).send({ error: `Backend service not found for ${service}` });
  }
  const url = `${backendServices[service]}${path}`;
  axios({
    method: req.method,
    url,
    headers: req.headers,
    data: req.body
  })
  .then(response => {
    res.status(response.status).send(response.data);
  })
  .catch(error => {
    console.error(`Error forwarding request to ${service}:`, error);
    res.status(500).send({ error: 'Internal Server Error' });
  });
});

const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`API gateway listening on port ${port}`);
});